__global__ void matrix_transpose(const float* __restrict__ input,
                                 float* __restrict__ output,
                                 int width, int height) {
    int xIndex = blockIdx.x * TILE_DIM + threadIdx.x;
    int yIndex = blockIdx.y * TILE_DIM + threadIdx.y;

